class SecureModelDownloader:
    """Securely download and validate pretrained models"""
    
    ALLOWED_DOMAINS = {
        'download.pytorch.org',
        'github.com',
        'huggingface.co',
        's3.amazonaws.com'
    }
    
    def __init__(self, cache_dir: str = './model_cache'):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.manifest_file = self.cache_dir / 'manifest.json'
        self.manifest = self._load_manifest()
    
    def _load_manifest(self) -> Dict:
        """Load trusted model manifest with checksums"""
        if self.manifest_file.exists():
            with open(self.manifest_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_manifest(self):
        """Save manifest to disk"""
        with open(self.manifest_file, 'w') as f:
            json.dump(self.manifest, f, indent=2)
    
    def _validate_url(self, url: str) -> bool:
        """Validate URL against allowlist"""
        try:
            parsed = urlparse(url)
            if parsed.scheme not in ['https']:
                logger.error(f"Only HTTPS URLs allowed, got: {parsed.scheme}")
                return False
            
            domain = parsed.netloc.lower()
            if not any(allowed in domain for allowed in self.ALLOWED_DOMAINS):
                logger.error(f"Domain not in allowlist: {domain}")
                return False
            
            return True
        except Exception as e:
            logger.error(f"URL validation error: {e}")
            return False
    
    def _compute_checksum(self, filepath: Path) -> str:
        """Compute SHA256 checksum of file"""
        sha256_hash = hashlib.sha256()
        with open(filepath, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    
    def _verify_checksum(self, filepath: Path, expected_checksum: str) -> bool:
        """Verify file checksum matches expected value"""
        actual_checksum = self._compute_checksum(filepath)
        if actual_checksum != expected_checksum:
            logger.error(f"Checksum mismatch! Expected: {expected_checksum}, Got: {actual_checksum}")
            return False
        return True
    
    def register_model(self, name: str, url: str, checksum: str):
        """Register a trusted model with its checksum"""
        if not self._validate_url(url):
            raise ValueError(f"Invalid or untrusted URL: {url}")
        
        self.manifest[name] = {
            'url': url,
            'checksum': checksum
        }
        self._save_manifest()
        logger.info(f"Registered model: {name}")
    
    def download_model(self, name: str) -> Path:
        """Download and verify a registered model"""
        if name not in self.manifest:
            raise ValueError(f"Model '{name}' not registered in manifest")
        
        model_info = self.manifest[name]
        url = model_info['url']
        expected_checksum = model_info['checksum']
        
        if not self._validate_url(url):
            raise ValueError(f"Invalid URL in manifest: {url}")
        
        filename = f"{name}.pth"
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            if self._verify_checksum(filepath, expected_checksum):
                logger.info(f"Using cached model: {name}")
                return filepath
            else:
                logger.warning(f"Cached model checksum mismatch, re-downloading: {name}")
                filepath.unlink()
        
        logger.info(f"Downloading model: {name} from {url}")
        
        try:
            response = requests.get(url, stream=True, timeout=300, verify=True)
            response.raise_for_status()
            
            with open(filepath, 'wb') as f:
                for chunk in response.iter_content(chunk_size=8192):
                    f.write(chunk)
            
            if not self._verify_checksum(filepath, expected_checksum):
                filepath.unlink()
                raise ValueError(f"Downloaded model checksum verification failed for {name}")
            
            logger.info(f"Successfully downloaded and verified: {name}")
            return filepath
            
        except Exception as e:
            if filepath.exists():
                filepath.unlink()
            logger.error(f"Download failed: {e}")
            raise
    
    def load_model(self, name: str, map_location: str = 'cpu') -> Dict:
        """Securely load a model checkpoint"""
        filepath = self.download_model(name)
        
        try:
            checkpoint = torch.load(
                filepath,
                map_location=map_location,
                weights_only=True
            )
            logger.info(f"Successfully loaded model: {name}")
            return checkpoint
        except Exception as e:
            logger.error(f"Failed to load model: {e}")
            raise


class CustomDataset(Dataset):
    """Example custom dataset for fine-tuning"""
    
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningPipeline:
    """Secure transfer learning pipeline"""
    
    def __init__(self, model_downloader: SecureModelDownloader):
        self.downloader = model_downloader
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    
    def load_pretrained_model(self, model_name: str, num_classes: int) -> nn.Module:
        """Load pretrained model and adapt for custom task"""
        checkpoint = self.downloader.load_model(model_name, map_location=str(self.device))
        
        model = self._create_model_architecture(checkpoint, num_classes)
        
        if 'state_dict' in checkpoint:
            state_dict = checkpoint['state_dict']
        elif 'model' in checkpoint:
            state_dict = checkpoint['model']
        else:
            state_dict = checkpoint
        
        model.load_state_dict(state_dict, strict=False)
        model = model.to(self.device)
        
        logger.info(f"Loaded pretrained model: {model_name}")
        return model
    
    def _create_model_architecture(self, checkpoint: Dict, num_classes: int) -> nn.Module:
        """Create model architecture based on checkpoint"""
        if 'arch' in checkpoint:
            arch = checkpoint['arch']
        else:
            arch = 'resnet18'
        
        if arch == 'resnet18':
            model = torch.hub.load('pytorch/vision:v0.10.0', 'resnet18', pretrained=False)
            num_ftrs = model.fc.in_features
            model.fc = nn.Linear(num_ftrs, num_classes)
        else:
            raise ValueError(f"Unsupported architecture: {arch}")
        
        return model
    
    def fine_tune(
        self,
        model: nn.Module,
        train_loader: DataLoader,
        val_loader: DataLoader,
        num_epochs: int = 10,
        learning_rate: float = 0.001,
        freeze_backbone: bool = True
    ) -> nn.Module:
        """Fine-tune model on custom dataset"""
        
        if freeze_backbone:
            for name, param in model.named_parameters():
                if 'fc' not in name:
                    param.requires_grad = False
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, model.parameters()), lr=learning_rate)
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=7, gamma=0.1)
        
        best_val_acc = 0.0
        
        for epoch in range(num_epochs):
            model.train()
            train_loss = 0.0
            train_correct = 0
            train_total = 0
            
            for inputs, labels in train_loader:
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)
                
                optimizer.zero_grad()
                outputs = model(inputs)
                loss = criterion(outputs, labels)
                loss.backward()
                optimizer.step()
                
                train_loss += loss.item()
                _, predicted = torch.max(outputs.data, 1)
                train_total += labels.size(0)
                train_correct += (predicted == labels).sum().item()
            
            train_acc = 100 * train_correct / train_total
            
            model.eval()
            val_loss = 0.0
            val_correct = 0
            val_total = 0
            
            with torch.no_grad():
                for inputs, labels in val_loader:
                    inputs = inputs.to(self.device)
                    labels = labels.to(self.device)
                    
                    outputs = model(inputs)
                    loss = criterion(outputs, labels)
                    
                    val_loss += loss.item()
                    _, predicted = torch.max(outputs.data, 1)
                    val_total += labels.size(0)
                    val_correct += (predicted == labels).sum().item()
            
            val_acc = 100 * val_correct / val_total
            
            logger.info(f'Epoch [{epoch+1}/{num_epochs}] '
                       f'Train Loss: {train_loss/len(train_loader):.4f} '
                       f'Train Acc: {train_acc:.2f}% '
                       f'Val Loss: {val_loss/len(val_loader):.4f} '
                       f'Val Acc: {val_acc:.2f}%')
            
            if val_acc > best_val_acc:
                best_val_acc = val_acc
            
            scheduler.step()
        
        logger.info(f'Best validation accuracy: {best_val_acc:.2f}%')
        return model
    
    def save_model(self, model: nn.Module, filepath: str):
        """Save fine-tuned model"""
        torch.save({
            'state_dict': model.state_dict(),
            'arch': model.__class__.__name__
        }, filepath)
        logger.info(f"Model saved to: {filepath}")


